package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.repository.OfficialResultRepository; import co.edu.elecciones.service.AuditService; import jakarta.servlet.http.HttpServletRequest; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/registraduria") public class RegistraduriaController { private final OfficialResultRepository results; private final AuditService audit; public RegistraduriaController(OfficialResultRepository r,AuditService a){results=r;audit=a;} @PostMapping("/sincronizar") public ApiResponse<Long> sync(HttpServletRequest req){ audit.log("SYNC","Registraduria",null,"Polling/mock ejecutado",req); return ApiResponse.ok("Sincronización mock ejecutada",results.count()); } @GetMapping("/estado") public ApiResponse<String> status(){ return ApiResponse.ok("API Registraduría disponible", "MOCK_CONNECTED"); }}
